                                "type": "string",
                                "description": "City name or coordinates",
                                "required": True,
                            }
                        }
                    },
                    "outputSchema": {
                        "type": "object",
                        "properties": {
                            "temperature": {"type": "number"},
                            "conditions": {"type": "string"},
                            "humidity": {"type": "number"},
                        },
                    },
                }
            },
        ),
    }

    app.add_middleware(PaymentMiddlewareASGI, routes=routes, server=server)
